    46→
    47→public class ChannelBuilders {
    48→    private static final Logger log = LoggerFactory.getLogger(ChannelBuilders.class);
    49→
    50→    private ChannelBuilders() { }
    51→
    52→    /**
    53→     * @param securityProtocol the securityProtocol
    54→     * @param contextType the contextType, it must be non-null if `securityProtocol` is SASL_*; it is ignored otherwise
    55→     * @param config client config
    56→     * @param listenerName the listenerName if contextType is SERVER or null otherwise
    57→     * @param clientSaslMechanism SASL mechanism if mode is CLIENT, ignored otherwise
    58→     * @param time the time instance
    59→     * @param logContext the log context instance
    60→     *
    61→     * @return the configured `ChannelBuilder`
    62→     * @throws IllegalArgumentException if `mode` invariants described above is not maintained
    63→     */
    64→    public static ChannelBuilder clientChannelBuilder(
    65→            SecurityProtocol securityProtocol,
    66→            JaasContext.Type contextType,
    67→            AbstractConfig config,
    68→            ListenerName listenerName,
    69→            String clientSaslMechanism,
    70→            Time time,
    71→            LogContext logContext) {
    72→
    73→        if (securityProtocol == SecurityProtocol.SASL_PLAINTEXT || securityProtocol == SecurityProtocol.SASL_SSL) {
    74→            if (contextType == null)
    75→                throw new IllegalArgumentException("`contextType` must be non-null if `securityProtocol` is `" + securityProtocol + "`");
    76→            if (clientSaslMechanism == null)
    77→                throw new IllegalArgumentException("`clientSaslMechanism` must be non-null in client mode if `securityProtocol` is `" + securityProtocol + "`");
    78→        }
    79→        return create(securityProtocol, ConnectionMode.CLIENT, contextType, config, listenerName, false, clientSaslMechanism,
    80→            null, null, time, logContext, null);
    81→    }
    82→
    83→    /**
    84→     * @param listenerName the listenerName
    85→     * @param isInterBrokerListener whether or not this listener is used for inter-broker requests
    86→     * @param securityProtocol the securityProtocol
    87→     * @param config server config
    88→     * @param credentialCache Credential cache for SASL/SCRAM if SCRAM is enabled
    89→     * @param tokenCache Delegation token cache
    90→     * @param time the time instance
    91→     * @param logContext the log context instance
    92→     * @param apiVersionSupplier supplier for ApiVersions responses sent prior to authentication
    93→     *
    94→     * @return the configured `ChannelBuilder`
    95→     */
    96→    public static ChannelBuilder serverChannelBuilder(ListenerName listenerName,
    97→                                                      boolean isInterBrokerListener,
    98→                                                      SecurityProtocol securityProtocol,
    99→                                                      AbstractConfig config,
   100→                                                      CredentialCache credentialCache,
   101→                                                      DelegationTokenCache tokenCache,
   102→                                                      Time time,
   103→                                                      LogContext logContext,
   104→                                                      Function<Short, ApiVersionsResponse> apiVersionSupplier) {
   105→        return create(securityProtocol, ConnectionMode.SERVER, JaasContext.Type.SERVER, config, listenerName,
   106→                isInterBrokerListener, null, credentialCache, tokenCache, time, logContext,
   107→                apiVersionSupplier);
   108→    }
   109→
   110→    private static ChannelBuilder create(SecurityProtocol securityProtocol,
   111→                                         ConnectionMode connectionMode,
   112→                                         JaasContext.Type contextType,
   113→                                         AbstractConfig config,
   114→                                         ListenerName listenerName,
   115→                                         boolean isInterBrokerListener,
   116→                                         String clientSaslMechanism,
   117→                                         CredentialCache credentialCache,
   118→                                         DelegationTokenCache tokenCache,
   119→                                         Time time,
   120→                                         LogContext logContext,
   121→                                         Function<Short, ApiVersionsResponse> apiVersionSupplier) {
   122→        Map<String, Object> configs = channelBuilderConfigs(config, listenerName);
   123→
   124→        ChannelBuilder channelBuilder;
   125→        switch (securityProtocol) {
   126→            case SSL:
   127→                requireNonNullMode(connectionMode, securityProtocol);
   128→                channelBuilder = new SslChannelBuilder(connectionMode, listenerName, isInterBrokerListener, logContext);
   129→                break;
   130→            case SASL_SSL:
   131→            case SASL_PLAINTEXT:
   132→                requireNonNullMode(connectionMode, securityProtocol);
   133→                Map<String, JaasContext> jaasContexts;
   134→                String sslClientAuthOverride = null;
   135→                if (connectionMode == ConnectionMode.SERVER) {
   136→                    @SuppressWarnings("unchecked")
   137→                    List<String> enabledMechanisms = (List<String>) configs.get(BrokerSecurityConfigs.SASL_ENABLED_MECHANISMS_CONFIG);
   138→                    jaasContexts = new HashMap<>(enabledMechanisms.size());
   139→                    for (String mechanism : enabledMechanisms)
   140→                        jaasContexts.put(mechanism, JaasContext.loadServerContext(listenerName, mechanism, configs));
   141→
   142→                    // SSL client authentication is enabled in brokers for SASL_SSL only if listener-prefixed config is specified.
   143→                    if (listenerName != null && securityProtocol == SecurityProtocol.SASL_SSL) {
   144→                        String configuredClientAuth = (String) configs.get(BrokerSecurityConfigs.SSL_CLIENT_AUTH_CONFIG);
   145→                        String listenerClientAuth = (String) config.originalsWithPrefix(listenerName.configPrefix(), true)
   146→                                .get(BrokerSecurityConfigs.SSL_CLIENT_AUTH_CONFIG);
