   148→                        // If `ssl.client.auth` is configured at the listener-level, we don't set an override and SslFactory
   149→                        // uses the value from `configs`. If not, we propagate `sslClientAuthOverride=NONE` to SslFactory and
   150→                        // it applies the override to the latest configs when it is configured or reconfigured. `Note that
   151→                        // ssl.client.auth` cannot be dynamically altered.
   152→                        if (listenerClientAuth == null) {
   153→                            sslClientAuthOverride = SslClientAuth.NONE.name().toLowerCase(Locale.ROOT);
   154→                            if (configuredClientAuth != null && !configuredClientAuth.equalsIgnoreCase(SslClientAuth.NONE.name())) {
   155→                                log.warn("Broker configuration '{}' is applied only to SSL listeners. Listener-prefixed configuration can be used" +
   156→                                        " to enable SSL client authentication for SASL_SSL listeners. In future releases, broker-wide option without" +
   157→                                        " listener prefix may be applied to SASL_SSL listeners as well. All configuration options intended for specific" +
   158→                                        " listeners should be listener-prefixed.", BrokerSecurityConfigs.SSL_CLIENT_AUTH_CONFIG);
   159→                            }
   160→                        }
   161→                    }
   162→                } else {
   163→                    // Use server context for inter-broker client connections and client context for other clients
   164→                    JaasContext jaasContext = contextType == JaasContext.Type.CLIENT ? JaasContext.loadClientContext(configs) :
   165→                            JaasContext.loadServerContext(listenerName, clientSaslMechanism, configs);
   166→                    jaasContexts = Collections.singletonMap(clientSaslMechanism, jaasContext);
   167→                }
   168→                channelBuilder = new SaslChannelBuilder(connectionMode,
   169→                        jaasContexts,
   170→                        securityProtocol,
   171→                        listenerName,
   172→                        isInterBrokerListener,
   173→                        clientSaslMechanism,
   174→                        credentialCache,
   175→                        tokenCache,
   176→                        sslClientAuthOverride,
   177→                        time,
   178→                        logContext,
   179→                        apiVersionSupplier);
   180→                break;
   181→            case PLAINTEXT:
   182→                channelBuilder = new PlaintextChannelBuilder(listenerName);
   183→                break;
   184→            default:
   185→                throw new IllegalArgumentException("Unexpected securityProtocol " + securityProtocol);
   186→        }
   187→
   188→        channelBuilder.configure(configs);
   189→        return channelBuilder;
   190→    }
   191→
   192→    /**
   193→     * @return a mutable RecordingMap. The elements got from RecordingMap are marked as "used".
   194→     */
   195→    @SuppressWarnings("unchecked")
   196→    static Map<String, Object> channelBuilderConfigs(final AbstractConfig config, final ListenerName listenerName) {
   197→        Map<String, Object> parsedConfigs;
   198→        if (listenerName == null)
   199→            parsedConfigs = (Map<String, Object>) config.values();
   200→        else
   201→            parsedConfigs = config.valuesWithPrefixOverride(listenerName.configPrefix());
   202→
   203→        config.originals().entrySet().stream()
   204→            .filter(e -> !parsedConfigs.containsKey(e.getKey())) // exclude already parsed configs
   205→            // exclude already parsed listener prefix configs
   206→            .filter(e -> !(listenerName != null && e.getKey().startsWith(listenerName.configPrefix()) &&
   207→                parsedConfigs.containsKey(e.getKey().substring(listenerName.configPrefix().length()))))
   208→            // exclude keys like `{mechanism}.some.prop` if "listener.name." prefix is present and key `some.prop` exists in parsed configs.
   209→            .filter(e -> !(listenerName != null && parsedConfigs.containsKey(e.getKey().substring(e.getKey().indexOf('.') + 1))))
   210→            .forEach(e -> parsedConfigs.put(e.getKey(), e.getValue()));
   211→        return parsedConfigs;
   212→    }
   213→
   214→    private static void requireNonNullMode(ConnectionMode connectionMode, SecurityProtocol securityProtocol) {
   215→        if (connectionMode == null)
   216→            throw new IllegalArgumentException("`mode` must be non-null if `securityProtocol` is `" + securityProtocol + "`");
   217→    }
