    84→     */
    85→    public static JaasContext loadClientContext(Map<String, ?> configs) {
    86→        Password dynamicJaasConfig = (Password) configs.get(SaslConfigs.SASL_JAAS_CONFIG);
    87→        return load(JaasContext.Type.CLIENT, null, GLOBAL_CONTEXT_NAME_CLIENT, dynamicJaasConfig);
    88→    }
    89→
    90→    static JaasContext load(JaasContext.Type contextType, String listenerContextName,
    91→                            String globalContextName, Password dynamicJaasConfig) {
    92→        if (dynamicJaasConfig != null) {
    93→            JaasConfig jaasConfig = new JaasConfig(globalContextName, dynamicJaasConfig.value());
    94→            AppConfigurationEntry[] contextModules = jaasConfig.getAppConfigurationEntry(globalContextName);
    95→            if (contextModules == null || contextModules.length == 0)
    96→                throw new IllegalArgumentException("JAAS config property does not contain any login modules");
    97→            else if (contextModules.length != 1)
    98→                throw new IllegalArgumentException("JAAS config property contains " + contextModules.length + " login modules, should be 1 module");
    99→
   100→            throwIfLoginModuleIsNotAllowed(contextModules[0]);
   101→            return new JaasContext(globalContextName, contextType, jaasConfig, dynamicJaasConfig);
   102→        } else
   103→            return defaultContext(contextType, listenerContextName, globalContextName);
   104→    }
   105→
   106→    private static void throwIfLoginModuleIsNotAllowed(AppConfigurationEntry appConfigurationEntry) {
   107→        Set<String> disallowedLoginModuleList = Arrays.stream(
   108→                System.getProperty(DISALLOWED_LOGIN_MODULES_CONFIG, DISALLOWED_LOGIN_MODULES_DEFAULT).split(","))
   109→                .map(String::trim)
   110→                .collect(Collectors.toSet());
   111→        String loginModuleName = appConfigurationEntry.getLoginModuleName().trim();
   112→        if (disallowedLoginModuleList.contains(loginModuleName)) {
   113→            throw new IllegalArgumentException(loginModuleName + " is not allowed. Update System property '"
   114→                    + DISALLOWED_LOGIN_MODULES_CONFIG + "' to allow " + loginModuleName);
   115→        }
   116→    }
   117→
   118→    private static JaasContext defaultContext(JaasContext.Type contextType, String listenerContextName,
   119→                                              String globalContextName) {
   120→        String jaasConfigFile = System.getProperty(JaasUtils.JAVA_LOGIN_CONFIG_PARAM);
   121→        if (jaasConfigFile == null) {
   122→            if (contextType == Type.CLIENT) {
   123→                LOG.debug("System property '" + JaasUtils.JAVA_LOGIN_CONFIG_PARAM + "' and Kafka SASL property '" +
   124→                        SaslConfigs.SASL_JAAS_CONFIG + "' are not set, using default JAAS configuration.");
   125→            } else {
   126→                LOG.debug("System property '" + JaasUtils.JAVA_LOGIN_CONFIG_PARAM + "' is not set, using default JAAS " +
   127→                        "configuration.");
   128→            }
   129→        }
   130→
   131→        Configuration jaasConfig = Configuration.getConfiguration();
   132→
   133→        AppConfigurationEntry[] configEntries = null;
   134→        String contextName = globalContextName;
   135→
   136→        if (listenerContextName != null) {
   137→            configEntries = jaasConfig.getAppConfigurationEntry(listenerContextName);
   138→            if (configEntries != null)
   139→                contextName = listenerContextName;
   140→        }
   141→
   142→        if (configEntries == null)
   143→            configEntries = jaasConfig.getAppConfigurationEntry(globalContextName);
   144→
   145→        if (configEntries == null) {
   146→            String listenerNameText = listenerContextName == null ? "" : " or '" + listenerContextName + "'";
   147→            String errorMessage = "Could not find a '" + globalContextName + "'" + listenerNameText + " entry in the JAAS " +
   148→                    "configuration. System property '" + JaasUtils.JAVA_LOGIN_CONFIG_PARAM + "' is " +
   149→                    (jaasConfigFile == null ? "not set" : jaasConfigFile);
   150→            throw new IllegalArgumentException(errorMessage);
   151→        }
   152→
   153→        for (AppConfigurationEntry appConfigurationEntry : configEntries) {
   154→            throwIfLoginModuleIsNotAllowed(appConfigurationEntry);
   155→        }
   156→        return new JaasContext(contextName, contextType, jaasConfig, null);
   157→    }
   158→
   159→    /**
   160→     * The type of the SASL login context, it should be SERVER for the broker and CLIENT for the clients (consumer, producer,
   161→     * etc.). This is used to validate behaviour (e.g. some functionality is only available in the broker or clients).
   162→     */
   163→    public enum Type { CLIENT, SERVER }
   164→
   165→    private final String name;
   166→    private final Type type;
   167→    private final Configuration configuration;
   168→    private final List<AppConfigurationEntry> configurationEntries;
   169→    private final Password dynamicJaasConfig;
   170→
   171→    public JaasContext(String name, Type type, Configuration configuration, Password dynamicJaasConfig) {
   172→        this.name = name;
   173→        this.type = type;
   174→        this.configuration = configuration;
   175→        AppConfigurationEntry[] entries = configuration.getAppConfigurationEntry(name);
   176→        if (entries == null)
   177→            throw new IllegalArgumentException("Could not find a '" + name + "' entry in this JAAS configuration.");
   178→        this.configurationEntries = List.of(entries);
   179→        this.dynamicJaasConfig = dynamicJaasConfig;
   180→    }
   181→
   182→    public String name() {
   183→        return name;
   184→    }
   185→
   186→    public Type type() {
   187→        return type;
   188→    }
   189→
   190→    public Configuration configuration() {
   191→        return configuration;
   192→    }
   193→
   194→    public List<AppConfigurationEntry> configurationEntries() {
   195→        return configurationEntries;
   196→    }
   197→
   198→    public Password dynamicJaasConfig() {
   199→        return dynamicJaasConfig;
   200→    }
   201→
   202→    /**
   203→     * Returns the configuration option for <code>key</code> from this context.
   204→     * If login module name is specified, return option value only from that module.
   205→     */
   206→    public static String configEntryOption(List<AppConfigurationEntry> configurationEntries, String key, String loginModuleName) {
   207→        for (AppConfigurationEntry entry : configurationEntries) {
   208→            if (loginModuleName != null && !loginModuleName.equals(entry.getLoginModuleName()))
   209→                continue;
   210→            Object val = entry.getOptions().get(key);
   211→            if (val != null)
   212→                return (String) val;
   213→        }
   214→        return null;
   215→    }
   216→
   217→}
