  val voterIds = QuorumConfig.parseVoterIds(quorumConfig.voters)
  def validateQuorumVotersAndQuorumBootstrapServerForKRaft(): Unit = {
    if (voterIds.isEmpty && quorumConfig.bootstrapServers.isEmpty) {
